		}
	}
	internal abstract class AsyncReadOrWriteRequest : AsyncProtocolRequest
	{
		protected BufferOffsetSize UserBuffer { get; }

		protected int CurrentSize { get; set; }

		public AsyncReadOrWriteRequest(MobileAuthenticatedStream parent, bool sync, byte[] buffer, int offset, int size)
			: base(parent, sync)
		{
			UserBuffer = new BufferOffsetSize(buffer, offset, size);
		}

		public override string ToString()
		{
			return $"[{base.Name}: {UserBuffer}]";
		}
	}
	internal class AsyncReadRequest : AsyncReadOrWriteRequest
	{
		public AsyncReadRequest(MobileAuthenticatedStream parent, bool sync, byte[] buffer, int offset, int size)
			: base(parent, sync, buffer, offset, size)
		{
		}

		protected override AsyncOperationStatus Run(AsyncOperationStatus status)
		{
			var (num, flag) = base.Parent.ProcessRead(base.UserBuffer);
			if (num < 0)
			{
				base.UserResult = -1;
				return AsyncOperationStatus.Complete;
			}
			base.CurrentSize += num;
			base.UserBuffer.Offset += num;
			base.UserBuffer.Size -= num;
			if (flag && base.CurrentSize == 0)
			{
				return AsyncOperationStatus.Continue;
			}
			base.UserResult = base.CurrentSize;
			return AsyncOperationStatus.Complete;
		}
	}
	internal class AsyncWriteRequest : AsyncReadOrWriteRequest
	{
		public AsyncWriteRequest(MobileAuthenticatedStream parent, bool sync, byte[] buffer, int offset, int size)
			: base(parent, sync, buffer, offset, size)
		{
		}

		protected override AsyncOperationStatus Run(AsyncOperationStatus status)
		{
			if (base.UserBuffer.Size == 0)
			{
				base.UserResult = base.CurrentSize;
				return AsyncOperationStatus.Complete;
			}
			var (num, flag) = base.Parent.ProcessWrite(base.UserBuffer);
			if (num < 0)
			{
				base.UserResult = -1;
				return AsyncOperationStatus.Complete;
			}
			base.CurrentSize += num;
			base.UserBuffer.Offset += num;
			base.UserBuffer.Size -= num;
			if (flag)
			{
				return AsyncOperationStatus.Continue;
			}
			base.UserResult = base.CurrentSize;
			return AsyncOperationStatus.Complete;
		}
	}
	internal class ChainValidationHelper : ICertificateValidator
	{
		private readonly WeakReference<SslStream> owner;

		private readonly MonoTlsSettings settings;

		private readonly MobileTlsProvider provider;

		private readonly ServerCertValidationCallback certValidationCallback;

		private readonly LocalCertSelectionCallback certSelectionCallback;

		private readonly MonoTlsStream tlsStream;

		private readonly HttpWebRequest request;

		public MonoTlsSettings Settings => settings;

		internal static ChainValidationHelper GetInternalValidator(SslStream owner, MobileTlsProvider provider, MonoTlsSettings settings)
		{
			if (settings == null)
			{
				return new ChainValidationHelper(owner, provider, null, cloneSettings: false, null);
			}
			if (settings.CertificateValidator != null)
			{
				return (ChainValidationHelper)settings.CertificateValidator;
			}
			return new ChainValidationHelper(owner, provider, settings, cloneSettings: false, null);
		}

		internal static ChainValidationHelper Create(MobileTlsProvider provider, ref MonoTlsSettings settings, MonoTlsStream stream)
		{
			ChainValidationHelper chainValidationHelper = new ChainValidationHelper(null, provider, settings, cloneSettings: true, stream);
			settings = chainValidationHelper.settings;
			return chainValidationHelper;
		}

		private ChainValidationHelper(SslStream owner, MobileTlsProvider provider, MonoTlsSettings settings, bool cloneSettings, MonoTlsStream stream)
		{
			if (settings == null)
			{
				settings = MonoTlsSettings.CopyDefaultSettings();
			}
			if (cloneSettings)
			{
				settings = settings.CloneWithValidator(this);
			}
			if (provider == null)
			{
				provider = MonoTlsProviderFactory.GetProviderInternal();
			}
			this.provider = provider;
			this.settings = settings;
			tlsStream = stream;
			if (owner != null)
			{
				this.owner = new WeakReference<SslStream>(owner);
			}
			bool flag = false;
			if (settings != null)
			{
				certValidationCallback = GetValidationCallback(settings);
				certSelectionCallback = CallbackHelpers.MonoToInternal(settings.ClientCertificateSelectionCallback);
				flag = settings.UseServicePointManagerCallback ?? (stream != null);
			}
			if (stream != null)
			{
				request = stream.Request;
				if (certValidationCallback == null)
				{
					certValidationCallback = request.ServerCertValidationCallback;
				}
				if (certSelectionCallback == null)
				{
					certSelectionCallback = DefaultSelectionCallback;
				}
				if (settings == null)
				{
					flag = true;
				}
			}
			if (flag && certValidationCallback == null)
			{
				certValidationCallback = ServicePointManager.ServerCertValidationCallback;
			}
		}

		private static ServerCertValidationCallback GetValidationCallback(MonoTlsSettings settings)
		{
			if (settings.RemoteCertificateValidationCallback == null)
			{
				return null;
			}
			return new ServerCertValidationCallback(delegate(object s, System.Security.Cryptography.X509Certificates.X509Certificate c, System.Security.Cryptography.X509Certificates.X509Chain ch, SslPolicyErrors e)
			{
				string text = null;
				if (s is SslStream sslStream)
				{
					text = sslStream.InternalTargetHost;
				}
				else if (s is HttpWebRequest httpWebRequest)
				{
					text = httpWebRequest.Host;
					if (!string.IsNullOrEmpty(text))
					{
						int num = text.IndexOf(':');
						if (num > 0)
						{
							text = text.Substring(0, num);
						}
					}
				}
				return settings.RemoteCertificateValidationCallback(text, c, ch, (MonoSslPolicyErrors)e);
			});
		}

		private static System.Security.Cryptography.X509Certificates.X509Certificate DefaultSelectionCallback(string targetHost, System.Security.Cryptography.X509Certificates.X509CertificateCollection localCertificates, System.Security.Cryptography.X509Certificates.X509Certificate remoteCertificate, string[] acceptableIssuers)
		{
			if (localCertificates == null || localCertificates.Count == 0)
			{
				return null;
			}
			return localCertificates[0];
		}

		public bool SelectClientCertificate(string targetHost, System.Security.Cryptography.X509Certificates.X509CertificateCollection localCertificates, System.Security.Cryptography.X509Certificates.X509Certificate remoteCertificate, string[] acceptableIssuers, out System.Security.Cryptography.X509Certificates.X509Certificate clientCertificate)
		{
			if (certSelectionCallback == null)
			{
				clientCertificate = null;
				return false;
			}
			clientCertificate = certSelectionCallback(targetHost, localCertificates, remoteCertificate, acceptableIssuers);
			return true;
		}

		public ValidationResult ValidateCertificate(string host, bool serverMode, System.Security.Cryptography.X509Certificates.X509Certificate leaf, System.Security.Cryptography.X509Certificates.X509Chain chain)
