				}
			}
		}

		public SslProtocols SslProtocol
		{
			get
			{
				lock (ioLock)
				{
					CheckThrow(authSuccessCheck: true);
					return (SslProtocols)xobileTlsContext.NegotiatedProtocol;
				}
			}
		}

		public System.Security.Cryptography.X509Certificates.X509Certificate RemoteCertificate
		{
			get
			{
				lock (ioLock)
				{
					CheckThrow(authSuccessCheck: true);
					return xobileTlsContext.RemoteCertificate;
				}
			}
		}

		public System.Security.Cryptography.X509Certificates.X509Certificate LocalCertificate
		{
			get
			{
				lock (ioLock)
				{
					CheckThrow(authSuccessCheck: true);
					return InternalLocalCertificate;
				}
			}
		}

		public System.Security.Cryptography.X509Certificates.X509Certificate InternalLocalCertificate
		{
