					try
					{
						mobileTlsProvider = CreateDefaultProviderImpl();
					}
					catch (Exception innerException)
					{
						throw new NotSupportedException("TLS Support not available.", innerException);
					}
					if (mobileTlsProvider == null)
					{
						throw new NotSupportedException("TLS Support not available.");
					}
					if (!providerCache.ContainsKey(mobileTlsProvider.ID))
					{
						providerCache.Add(mobileTlsProvider.ID, mobileTlsProvider);
					}
					defaultProvider = mobileTlsProvider;
					initialized = true;
				}
			}
		}

		private static void InitializeProviderRegistration()
		{
			lock (locker)
			{
				if (providerRegistration == null)
				{
					providerRegistration = new Dictionary<string, Tuple<Guid, string>>();
					providerCache = new Dictionary<Guid, MobileTlsProvider>();
					PopulateProviders();
				}
			}
		}

		private static void PopulateProviders()
		{
			Tuple<Guid, string> value = new Tuple<Guid, string>(BtlsId, typeof(MonoBtlsProvider).FullName);
			providerRegistration.Add("default", value);
			providerRegistration.Add("legacy", value);
			providerRegistration.Add("btls", value);
		}

		[MethodImpl(MethodImplOptions.InternalCall)]
		internal static extern bool IsBtlsSupported();

		private static MobileTlsProvider CreateDefaultProviderImpl()
		{
			string environmentVariable = Environment.GetEnvironmentVariable("XA_TLS_PROVIDER");
			switch (environmentVariable)
			{
			case null:
			case "default":
			case "legacy":
			case "btls":
				if (!IsBtlsSupported())
				{
					throw new NotSupportedException("BTLS in not supported!");
				}
				return new MonoBtlsProvider();
			default:
				throw new NotSupportedException("Invalid TLS Provider: `" + environmentVariable + "'.");
			}
		}

		internal static MobileTlsProvider GetProvider()
		{
			return GetProviderInternal();
		}
	}
	internal class MonoTlsStream : IDisposable
	{
		private readonly MobileTlsProvider provider;

		private readonly NetworkStream networkStream;

		private readonly HttpWebRequest request;

		private readonly MonoTlsSettings settings;

		private SslStream sslStream;

		private readonly object sslStreamLock = new object();

		private WebExceptionStatus status;

		internal HttpWebRequest Request => request;

		internal WebExceptionStatus ExceptionStatus => status;

		internal bool CertificateValidationFailed { get; set; }

		public MonoTlsStream(HttpWebRequest request, NetworkStream networkStream)
		{
			this.request = request;
			this.networkStream = networkStream;
			settings = request.TlsSettings;
			provider = request.TlsProvider ?? MonoTlsProviderFactory.GetProviderInternal();
			status = WebExceptionStatus.SecureChannelFailure;
			ChainValidationHelper.Create(provider, ref settings, this);
		}

		internal async Task<Stream> CreateStream(WebConnectionTunnel tunnel, CancellationToken cancellationToken)
		{
			Socket socket = networkStream.InternalSocket;
			sslStream = new SslStream(networkStream, leaveInnerStreamOpen: false, provider, settings);
			try
			{
				string text = request.Host;
				if (!string.IsNullOrEmpty(text))
				{
					int num = text.IndexOf(':');
					if (num > 0)
					{
						text = text.Substring(0, num);
					}
				}
				await sslStream.AuthenticateAsClientAsync(text, request.ClientCertificates, (SslProtocols)ServicePointManager.SecurityProtocol, ServicePointManager.CheckCertificateRevocationList).ConfigureAwait(continueOnCapturedContext: false);
				status = WebExceptionStatus.Success;
				request.ServicePoint.UpdateClientCertificate(sslStream.LocalCertificate);
			}
			catch (Exception)
			{
				if (socket.CleanedUp)
				{
					status = WebExceptionStatus.RequestCanceled;
				}
				else if (CertificateValidationFailed)
				{
					status = WebExceptionStatus.TrustFailure;
				}
				else
				{
					status = WebExceptionStatus.SecureChannelFailure;
				}
				request.ServicePoint.UpdateClientCertificate(null);
				CloseSslStream();
				throw;
			}
			try
			{
				if (tunnel?.Data != null)
				{
					await sslStream.WriteAsync(tunnel.Data, 0, tunnel.Data.Length, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
				}
			}
			catch
			{
				status = WebExceptionStatus.SendFailure;
				CloseSslStream();
				throw;
			}
			return sslStream;
		}

		public void Dispose()
		{
			CloseSslStream();
		}

		private void CloseSslStream()
		{
			lock (sslStreamLock)
			{
				if (sslStream != null)
				{
					sslStream.Dispose();
					sslStream = null;
				}
			}
		}
	}
