	internal class X509CertificateImplBtls : X509Certificate2ImplUnix
	{
		private MonoBtlsX509 x509;

		private MonoBtlsKey nativePrivateKey;

		private X509CertificateImplCollection intermediateCerts;

		public override bool IsValid
		{
			get
			{
				if (x509 != null)
				{
					return x509.IsValid;
				}
				return false;
			}
		}

		internal MonoBtlsX509 X509
		{
			get
			{
				ThrowIfContextInvalid();
				return x509;
			}
		}

		internal MonoBtlsKey NativePrivateKey
		{
			get
			{
				ThrowIfContextInvalid();
				return nativePrivateKey;
			}
		}

		internal override X509CertificateImplCollection IntermediateCertificates => intermediateCerts;

		public override bool HasPrivateKey => nativePrivateKey != null;

		public override AsymmetricAlgorithm PrivateKey
		{
			get
			{
				if (nativePrivateKey == null)
				{
					return null;
				}
				return PKCS8.PrivateKeyInfo.DecodeRSA(nativePrivateKey.GetBytes(include_private_bits: true));
			}
			set
			{
				if (nativePrivateKey != null)
				{
					nativePrivateKey.Dispose();
				}
				try
				{
					if (value != null)
					{
						nativePrivateKey = MonoBtlsKey.CreateFromRSAPrivateKey((RSA)value);
					}
				}
				catch
				{
					nativePrivateKey = null;
				}
			}
		}

		internal X509CertificateImplBtls(MonoBtlsX509 x509)
		{
			this.x509 = x509.Copy();
		}

		private X509CertificateImplBtls(X509CertificateImplBtls other)
		{
			x509 = ((other.x509 != null) ? other.x509.Copy() : null);
			nativePrivateKey = ((other.nativePrivateKey != null) ? other.nativePrivateKey.Copy() : null);
			if (other.intermediateCerts != null)
			{
				intermediateCerts = other.intermediateCerts.Clone();
			}
		}

		internal X509CertificateImplBtls(byte[] data, MonoBtlsX509Format format)
		{
			x509 = MonoBtlsX509.LoadFromData(data, format);
		}

		internal X509CertificateImplBtls(byte[] data, SafePasswordHandle password, X509KeyStorageFlags keyStorageFlags)
		{
			if (password == null || password.IsInvalid)
			{
				try
				{
					Import(data);
					return;
				}
				catch (Exception inner)
				{
					try
					{
						ImportPkcs12(data, null);
						return;
					}
					catch
					{
						try
						{
							ImportAuthenticode(data);
							return;
						}
						catch
						{
							throw new CryptographicException(Locale.GetText("Unable to decode certificate."), inner);
						}
					}
				}
			}
			try
			{
				ImportPkcs12(data, password);
			}
			catch (Exception inner2)
			{
				try
				{
					Import(data);
				}
				catch
				{
					try
					{
						ImportAuthenticode(data);
					}
					catch
					{
						throw new CryptographicException(Locale.GetText("Unable to decode certificate."), inner2);
					}
				}
			}
		}

		public override X509CertificateImpl Clone()
		{
			ThrowIfContextInvalid();
			return new X509CertificateImplBtls(this);
		}

		protected override byte[] GetRawCertData()
		{
			ThrowIfContextInvalid();
			return X509.GetRawData(MonoBtlsX509Format.DER);
		}

		protected override void Dispose(bool disposing)
		{
			if (x509 != null)
			{
				x509.Dispose();
				x509 = null;
			}
		}

		public override RSA GetRSAPrivateKey()
		{
			if (nativePrivateKey == null)
			{
				return null;
			}
			return PKCS8.PrivateKeyInfo.DecodeRSA(nativePrivateKey.GetBytes(include_private_bits: true));
		}

		public override DSA GetDSAPrivateKey()
		{
			throw new PlatformNotSupportedException();
		}

		private void Import(byte[] data)
		{
			if (data != null)
			{
				if (data.Length != 0 && data[0] != 48)
				{
					x509 = MonoBtlsX509.LoadFromData(data, MonoBtlsX509Format.PEM);
				}
				else
				{
					x509 = MonoBtlsX509.LoadFromData(data, MonoBtlsX509Format.DER);
				}
			}
		}

		private void ImportPkcs12(byte[] data, SafePasswordHandle password)
		{
			using MonoBtlsPkcs12 monoBtlsPkcs = new MonoBtlsPkcs12();
			if (password == null || password.IsInvalid)
			{
				try
				{
					monoBtlsPkcs.Import(data, null);
				}
				catch
				{
					using SafePasswordHandle password2 = new SafePasswordHandle(string.Empty);
					monoBtlsPkcs.Import(data, password2);
				}
			}
			else
			{
				monoBtlsPkcs.Import(data, password);
			}
			x509 = monoBtlsPkcs.GetCertificate(0);
			if (monoBtlsPkcs.HasPrivateKey)
			{
				nativePrivateKey = monoBtlsPkcs.GetPrivateKey();
			}
			if (monoBtlsPkcs.Count <= 1)
			{
				return;
			}
			intermediateCerts = new X509CertificateImplCollection();
			for (int i = 0; i < monoBtlsPkcs.Count; i++)
			{
				using MonoBtlsX509 a = monoBtlsPkcs.GetCertificate(i);
				if (MonoBtlsX509.Compare(a, x509) != 0)
				{
					X509CertificateImplBtls impl = new X509CertificateImplBtls(a);
					intermediateCerts.Add(impl, takeOwnership: true);
				}
			}
		}

		private void ImportAuthenticode(byte[] data)
		{
			if (data != null)
			{
				AuthenticodeDeformatter authenticodeDeformatter = new AuthenticodeDeformatter(data);
				Import(authenticodeDeformatter.SigningCertificate.RawData);
			}
		}

		public override bool Verify(X509Certificate2 thisCertificate)
		{
			using MonoBtlsX509Chain monoBtlsX509Chain = new MonoBtlsX509Chain();
			monoBtlsX509Chain.AddCertificate(x509.Copy());
			if (intermediateCerts != null)
			{
				for (int i = 0; i < intermediateCerts.Count; i++)
				{
					X509CertificateImplBtls x509CertificateImplBtls = (X509CertificateImplBtls)intermediateCerts[i];
					monoBtlsX509Chain.AddCertificate(x509CertificateImplBtls.x509.Copy());
				}
			}
			return MonoBtlsProvider.ValidateCertificate(monoBtlsX509Chain, null);
		}
	}
	internal class X509ChainImplBtls : X509ChainImpl
	{
		private MonoBtlsX509StoreCtx storeCtx;

		private MonoBtlsX509Chain chain;

		private MonoBtlsX509Chain untrustedChain;

		private X509ChainElementCollection elements;

		private X509Certificate2Collection untrusted;

		private X509Certificate2[] certificates;

		private X509ChainPolicy policy;

		private List<X509ChainStatus> chainStatusList;

		public override bool IsValid
		{
			get
			{
				if (chain != null)
				{
					return chain.IsValid;
				}
				return false;
			}
		}

		internal MonoBtlsX509StoreCtx StoreCtx
		{
			get
			{
				ThrowIfContextInvalid();
				return storeCtx;
			}
		}

		public override X509ChainElementCollection ChainElements
		{
			get
			{
				ThrowIfContextInvalid();
				if (elements != null)
				{
					return elements;
				}
				elements = new X509ChainElementCollection();
				certificates = new X509Certificate2[chain.Count];
				for (int i = 0; i < certificates.Length; i++)
				{
					using (X509CertificateImplBtls impl = new X509CertificateImplBtls(chain.GetCertificate(i)))
					{
						certificates[i] = new X509Certificate2(impl);
					}
					elements.Add(certificates[i]);
				}
				return elements;
			}
		}

		public override X509ChainPolicy ChainPolicy => policy;

		public override X509ChainStatus[] ChainStatus => chainStatusList?.ToArray() ?? new X509ChainStatus[0];

		internal X509ChainImplBtls(MonoBtlsX509Chain chain)
		{
			this.chain = chain.Copy();
			policy = new X509ChainPolicy();
		}

		internal X509ChainImplBtls(MonoBtlsX509StoreCtx storeCtx)
		{
			this.storeCtx = storeCtx.Copy();
			chain = storeCtx.GetChain();
			policy = new X509ChainPolicy();
			untrustedChain = storeCtx.GetUntrusted();
			if (untrustedChain == null)
			{
				return;
			}
			untrusted = new X509Certificate2Collection();
			policy.ExtraStore = untrusted;
			for (int i = 0; i < untrustedChain.Count; i++)
			{
				using X509CertificateImplBtls impl = new X509CertificateImplBtls(untrustedChain.GetCertificate(i));
				untrusted.Add(new X509Certificate2(impl));
			}
		}

		public override void AddStatus(System.Security.Cryptography.X509Certificates.X509ChainStatusFlags errorCode)
		{
			if (chainStatusList == null)
			{
				chainStatusList = new List<X509ChainStatus>();
			}
			chainStatusList.Add(new X509ChainStatus(errorCode));
		}

		public override bool Build(X509Certificate2 certificate)
		{
			return false;
		}

		public override void Reset()
		{
			if (certificates != null)
			{
				X509Certificate2[] array = certificates;
				for (int i = 0; i < array.Length; i++)
				{
					array[i].Dispose();
				}
				certificates = null;
			}
			if (elements != null)
			{
				elements.Clear();
				elements = null;
			}
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing)
			{
				if (chain != null)
				{
					chain.Dispose();
					chain = null;
				}
				if (storeCtx != null)
				{
					storeCtx.Dispose();
					storeCtx = null;
				}
				if (untrustedChain != null)
				{
					untrustedChain.Dispose();
					untrustedChain = null;
				}
				if (untrusted != null)
				{
					X509Certificate2Enumerator enumerator = untrusted.GetEnumerator();
					while (enumerator.MoveNext())
					{
						enumerator.Current.Dispose();
					}
					untrusted = null;
				}
				if (certificates != null)
				{
					X509Certificate2[] array = certificates;
					for (int i = 0; i < array.Length; i++)
					{
						array[i].Dispose();
					}
					certificates = null;
				}
			}
			base.Dispose(disposing);
		}
	}
	internal class X509PalImplBtls : X509PalImpl
	{
		private MonoBtlsProvider Provider { get; }

		public X509PalImplBtls(MonoTlsProvider provider)
		{
			Provider = (MonoBtlsProvider)provider;
		}

		public override X509CertificateImpl Import(byte[] data)
		{
			return Provider.GetNativeCertificate(data, (string)null, X509KeyStorageFlags.DefaultKeySet);
		}

		public override X509Certificate2Impl Import(byte[] data, SafePasswordHandle password, X509KeyStorageFlags keyStorageFlags)
		{
			return Provider.GetNativeCertificate(data, password, keyStorageFlags);
		}

		public override X509Certificate2Impl Import(System.Security.Cryptography.X509Certificates.X509Certificate cert)
		{
			return Provider.GetNativeCertificate(cert);
		}
	}
