					{
						UpdateTimer();
					}
				}
			}
		}

		[Category("Behavior")]
		[TimersDescription("Indicates whether the timer is enabled to fire events at a defined interval.")]
		[DefaultValue(false)]
		public bool Enabled
		{
			get
			{
				return enabled;
			}
			set
			{
				if (base.DesignMode)
				{
					delayedEnable = value;
					enabled = value;
				}
				else if (initializing)
				{
					delayedEnable = value;
				}
				else
				{
					if (enabled == value)
					{
						return;
					}
					if (!value)
					{
						if (timer != null)
						{
							cookie = null;
							timer.Dispose();
							timer = null;
						}
						enabled = value;
						return;
					}
					enabled = value;
					if (timer == null)
					{
						if (disposed)
						{
							throw new ObjectDisposedException(GetType().Name);
						}
						int num = CalculateRoundedInterval(interval);
						cookie = new object();
