		private void Ldc(int i)
		{
			if (i <= 127 && i >= -128)
			{
				_ilg.Emit(OpCodes.Ldc_I4_S, (byte)i);
			}
			else
			{
				_ilg.Emit(OpCodes.Ldc_I4, i);
			}
		}

