			switch (c)
			{
			case 'x':
				return ScanHex(2);
			case 'u':
				return ScanHex(4);
			case 'a':
				return '\a';
			case 'b':
				return '\b';
			case 'e':
				return '\u001b';
			case 'f':
				return '\f';
			case 'n':
				return '\n';
			case 'r':
				return '\r';
			case 't':
				return '\t';
			case 'v':
				return '\v';
			case 'c':
				return ScanControl();
