			int num = Textpos();
			while (CharsRight() > 0)
			{
				c = RightCharMoveRight();
				if (!RegexCharClass.IsWordChar(c) && c != '-')
				{
					MoveLeft();
					break;
				}
			}
			string result = _pattern.Substring(num, Textpos() - num);
			if (CharsRight() == 0 || RightCharMoveRight() != '}')
			{
