				}
				return 41;
			case 'B':
				if (!UseOptionE())
				{
					return 17;
				}
				return 42;
			case 'A':
				return 18;
			case 'G':
				return 19;
			case 'Z':
				return 20;
			case 'z':
				return 21;
			default:
				return 22;
			}
		}

		private static RegexOptions OptionFromCode(char ch)
