				'r' => RegexOptions.RightToLeft, 
				'm' => RegexOptions.Multiline, 
				'n' => RegexOptions.ExplicitCapture, 
				's' => RegexOptions.Singleline, 
				'x' => RegexOptions.IgnorePatternWhitespace, 
				'e' => RegexOptions.ECMAScript, 
				_ => RegexOptions.None, 
			};
