					}
					break;
				case '#':
					if (UseOptionX())
					{
						MoveLeft();
						ScanBlank();
					}
					break;
				case '[':
					ScanCharClass(caseInsensitive: false, scanOnly: true);
					break;
				case ')':
					if (!EmptyOptionsStack())
					{
						PopOptions();
					}
					break;
				case '(':
					if (CharsRight() >= 2 && RightChar(1) == '#' && RightChar() == '?')
					{
