				}
				if (num < -4)
				{
					sb.Append(match.GroupToStringImpl(-5 - num));
					continue;
				}
				switch (-5 - num)
				{
				case -1:
					sb.Append(match.GetLeftSubstring());
					break;
				case -2:
					sb.Append(match.GetRightSubstring());
					break;
				case -3:
					sb.Append(match.LastGroupToStringImpl());
					break;
				case -4:
					sb.Append(match.Text);
					break;
				}
			}
		}

