	internal class AsyncStreamReader
	{
		private Stream stream;

		private Encoding encoding;

		private Decoder decoder;

		private byte[] byteBuffer;

		private char[] charBuffer;

		private bool cancelOperation;

		private ManualResetEvent eofEvent;

		private object syncObject;

		private IAsyncResult asyncReadResult;

		public virtual void Close()
		{
			Dispose(disposing: true);
		}

		protected virtual void Dispose(bool disposing)
		{
			lock (syncObject)
			{
				if (disposing && stream != null)
				{
					if (asyncReadResult != null && !asyncReadResult.IsCompleted && stream is FileStream)
					{
						SafeHandle safeFileHandle = ((FileStream)stream).SafeFileHandle;
						MonoIOError error;
						while (!asyncReadResult.IsCompleted && (MonoIO.Cancel(safeFileHandle, out error) || error != MonoIOError.ERROR_NOT_SUPPORTED))
						{
							asyncReadResult.AsyncWaitHandle.WaitOne(200);
						}
					}
					stream.Close();
				}
				if (stream != null)
				{
					stream = null;
					encoding = null;
					decoder = null;
					byteBuffer = null;
					charBuffer = null;
				}
				if (eofEvent != null)
				{
					eofEvent.Close();
					eofEvent = null;
				}
			}
		}

		internal void CancelOperation()
		{
			cancelOperation = true;
		}

		internal void WaitUtilEOF()
		{
			if (eofEvent != null)
			{
				eofEvent.WaitOne();
				eofEvent.Close();
				eofEvent = null;
			}
		}
	}
	[MonitoringDescription("Provides access to local and remote processes, enabling starting and stopping of local processes.")]
	[DefaultEvent("Exited")]
