				PlatformID platform = Environment.OSVersion.Platform;
				if (platform == PlatformID.Win32S || platform == PlatformID.Win32Windows || platform == PlatformID.Win32NT || platform == PlatformID.WinCE)
				{
					return true;
				}
				return false;
			}
		}

