			{
				throw new CryptographicException("ASN1 corrupted data.");
			}
			byte num = data[position];
			byte b = (byte)(num & 0x1F);
			if (b == 31)
			{
				throw new CryptographicException("ASN1 corrupted data.");
			}
			if ((num & 0x80) != 0 || (uint)(expected & (DerTag)31) == b)
			{
				return;
			}
			throw new CryptographicException("ASN1 corrupted data.");
		}

		private int EatLength()
		{
