	public sealed class Oid
	{
		private string _value;

		private string _friendlyName;

		private OidGroup _group;

		public string Value
		{
			get
			{
				return _value;
			}
			set
			{
				_value = value;
			}
		}

		public string FriendlyName
		{
			get
			{
				if (_friendlyName == null && _value != null)
				{
					_friendlyName = OidLookup.ToFriendlyName(_value, _group, fallBackToAllGroups: true);
				}
				return _friendlyName;
			}
		}

		public Oid()
		{
		}

		public Oid(string oid)
		{
			string text = OidLookup.ToOid(oid, OidGroup.All, fallBackToAllGroups: false);
			if (text == null)
			{
				text = oid;
			}
			Value = text;
			_group = OidGroup.All;
		}

		public Oid(string value, string friendlyName)
		{
			_value = value;
			_friendlyName = friendlyName;
		}

		public Oid(Oid oid)
		{
			if (oid == null)
			{
				throw new ArgumentNullException("oid");
			}
			_value = oid._value;
			_friendlyName = oid._friendlyName;
			_group = oid._group;
		}

		public static Oid FromOidValue(string oidValue, OidGroup group)
		{
			if (oidValue == null)
			{
				throw new ArgumentNullException("oidValue");
			}
			string text = OidLookup.ToFriendlyName(oidValue, group, fallBackToAllGroups: false);
			if (text == null)
			{
				throw new CryptographicException("The OID value is invalid.");
			}
			return new Oid(oidValue, text, group);
		}

		private Oid(string value, string friendlyName, OidGroup group)
		{
			_value = value;
			_friendlyName = friendlyName;
			_group = group;
		}
	}
	public sealed class OidCollection : ICollection, IEnumerable
	{
		private readonly List<Oid> _list;

		public Oid this[int index] => _list[index];

		public int Count => _list.Count;

		public bool IsSynchronized => false;

		public object SyncRoot => this;

		public OidCollection()
		{
			_list = new List<Oid>();
		}

		public int Add(Oid oid)
		{
			int count = _list.Count;
			_list.Add(oid);
			return count;
		}

		public OidEnumerator GetEnumerator()
		{
			return new OidEnumerator(this);
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}

		void ICollection.CopyTo(Array array, int index)
		{
			if (array == null)
			{
				throw new ArgumentNullException("array");
			}
			if (array.Rank != 1)
			{
				throw new ArgumentException("Only single dimensional arrays are supported for the requested action.");
			}
			if (index < 0 || index >= array.Length)
			{
				throw new ArgumentOutOfRangeException("index", "Index was out of range. Must be non-negative and less than the size of the collection.");
			}
			if (index + Count > array.Length)
			{
				throw new ArgumentException("Offset and length were out of bounds for the array or count is greater than the number of elements from index to the end of the source collection.");
			}
			for (int i = 0; i < Count; i++)
			{
				array.SetValue(this[i], index);
				index++;
			}
		}
	}
	public sealed class OidEnumerator : IEnumerator
	{
		private readonly OidCollection _oids;

		private int _current;

		public Oid Current => _oids[_current];

		object IEnumerator.Current => Current;

		internal OidEnumerator(OidCollection oids)
		{
			_oids = oids;
			_current = -1;
		}

		public bool MoveNext()
		{
			if (_current >= _oids.Count - 1)
			{
				return false;
			}
			_current++;
			return true;
		}

		public void Reset()
		{
			_current = -1;
		}
	}
