	public sealed class PublicKey
	{
		private AsnEncodedData _keyValue;

		private AsnEncodedData _params;

		private Oid _oid;

		private static byte[] Empty = new byte[0];

		public AsnEncodedData EncodedKeyValue => _keyValue;

		public AsnEncodedData EncodedParameters => _params;

		public AsymmetricAlgorithm Key
		{
			get
			{
				string value = _oid.Value;
				if (!(value == "1.2.840.113549.1.1.1"))
				{
					if (value == "1.2.840.10040.4.1")
					{
						return DecodeDSA(_keyValue.RawData, _params.RawData);
					}
					throw new NotSupportedException(Locale.GetText("Cannot decode public key from unknown OID '{0}'.", _oid.Value));
				}
				return DecodeRSA(_keyValue.RawData);
			}
		}

		public Oid Oid => _oid;

		public PublicKey(Oid oid, AsnEncodedData parameters, AsnEncodedData keyValue)
		{
			if (oid == null)
			{
				throw new ArgumentNullException("oid");
			}
			if (parameters == null)
			{
				throw new ArgumentNullException("parameters");
			}
			if (keyValue == null)
			{
				throw new ArgumentNullException("keyValue");
			}
			_oid = new Oid(oid);
			_params = new AsnEncodedData(parameters);
			_keyValue = new AsnEncodedData(keyValue);
		}

		private static byte[] GetUnsignedBigInteger(byte[] integer)
		{
			if (integer[0] != 0)
			{
				return integer;
			}
			int num = integer.Length - 1;
			byte[] array = new byte[num];
			Buffer.BlockCopy(integer, 1, array, 0, num);
			return array;
		}

		internal static DSA DecodeDSA(byte[] rawPublicKey, byte[] rawParameters)
		{
			DSAParameters parameters = default(DSAParameters);
			try
			{
				ASN1 aSN = new ASN1(rawPublicKey);
				if (aSN.Tag != 2)
				{
					throw new CryptographicException(Locale.GetText("Missing DSA Y integer."));
				}
				parameters.Y = GetUnsignedBigInteger(aSN.Value);
				ASN1 aSN2 = new ASN1(rawParameters);
				if (aSN2 == null || aSN2.Tag != 48 || aSN2.Count < 3)
				{
					throw new CryptographicException(Locale.GetText("Missing DSA parameters."));
				}
				if (aSN2[0].Tag != 2 || aSN2[1].Tag != 2 || aSN2[2].Tag != 2)
				{
					throw new CryptographicException(Locale.GetText("Invalid DSA parameters."));
				}
				parameters.P = GetUnsignedBigInteger(aSN2[0].Value);
				parameters.Q = GetUnsignedBigInteger(aSN2[1].Value);
				parameters.G = GetUnsignedBigInteger(aSN2[2].Value);
			}
			catch (Exception inner)
			{
				throw new CryptographicException(Locale.GetText("Error decoding the ASN.1 structure."), inner);
			}
			DSACryptoServiceProvider dSACryptoServiceProvider = new DSACryptoServiceProvider(parameters.Y.Length << 3);
			dSACryptoServiceProvider.ImportParameters(parameters);
			return dSACryptoServiceProvider;
		}

		internal static RSA DecodeRSA(byte[] rawPublicKey)
		{
			RSAParameters parameters = default(RSAParameters);
			try
			{
				ASN1 aSN = new ASN1(rawPublicKey);
				if (aSN.Count == 0)
				{
					throw new CryptographicException(Locale.GetText("Missing RSA modulus and exponent."));
				}
				ASN1 aSN2 = aSN[0];
				if (aSN2 == null || aSN2.Tag != 2)
				{
					throw new CryptographicException(Locale.GetText("Missing RSA modulus."));
				}
				ASN1 aSN3 = aSN[1];
				if (aSN3.Tag != 2)
				{
					throw new CryptographicException(Locale.GetText("Missing RSA public exponent."));
				}
				parameters.Modulus = GetUnsignedBigInteger(aSN2.Value);
				parameters.Exponent = aSN3.Value;
			}
			catch (Exception inner)
			{
				throw new CryptographicException(Locale.GetText("Error decoding the ASN.1 structure."), inner);
			}
			RSACryptoServiceProvider rSACryptoServiceProvider = new RSACryptoServiceProvider(parameters.Modulus.Length << 3);
			rSACryptoServiceProvider.ImportParameters(parameters);
			return rSACryptoServiceProvider;
		}
	}
	public sealed class X500DistinguishedName : AsnEncodedData
	{
		private string name;

		private byte[] canonEncoding;

		public string Name => name;

		public X500DistinguishedName(byte[] encodedDistinguishedName)
		{
			if (encodedDistinguishedName == null)
			{
				throw new ArgumentNullException("encodedDistinguishedName");
			}
			base.Oid = new Oid();
			base.RawData = encodedDistinguishedName;
			if (encodedDistinguishedName.Length != 0)
			{
				DecodeRawData();
			}
			else
			{
				name = string.Empty;
			}
		}

		public X500DistinguishedName(string distinguishedName)
			: this(distinguishedName, X500DistinguishedNameFlags.Reversed)
		{
		}

		public X500DistinguishedName(string distinguishedName, X500DistinguishedNameFlags flag)
		{
			if (distinguishedName == null)
			{
				throw new ArgumentNullException("distinguishedName");
			}
			if (flag != X500DistinguishedNameFlags.None && (flag & (X500DistinguishedNameFlags.Reversed | X500DistinguishedNameFlags.UseSemicolons | X500DistinguishedNameFlags.DoNotUsePlusSign | X500DistinguishedNameFlags.DoNotUseQuotes | X500DistinguishedNameFlags.UseCommas | X500DistinguishedNameFlags.UseNewLines | X500DistinguishedNameFlags.UseUTF8Encoding | X500DistinguishedNameFlags.UseT61Encoding | X500DistinguishedNameFlags.ForceUTF8Encoding)) == 0)
			{
				throw new ArgumentException("flag");
			}
			base.Oid = new Oid();
			if (distinguishedName.Length == 0)
			{
				base.RawData = new byte[2] { 48, 0 };
				DecodeRawData();
				return;
			}
			ASN1 aSN = X501.FromString(distinguishedName);
			if ((flag & X500DistinguishedNameFlags.Reversed) != X500DistinguishedNameFlags.None)
			{
				ASN1 aSN2 = new ASN1(48);
				for (int num = aSN.Count - 1; num >= 0; num--)
				{
					aSN2.Add(aSN[num]);
				}
				aSN = aSN2;
			}
			base.RawData = aSN.GetBytes();
			if (flag == X500DistinguishedNameFlags.None)
			{
				name = distinguishedName;
			}
			else
			{
				name = Decode(flag);
			}
		}

		public string Decode(X500DistinguishedNameFlags flag)
		{
			if (flag != X500DistinguishedNameFlags.None && (flag & (X500DistinguishedNameFlags.Reversed | X500DistinguishedNameFlags.UseSemicolons | X500DistinguishedNameFlags.DoNotUsePlusSign | X500DistinguishedNameFlags.DoNotUseQuotes | X500DistinguishedNameFlags.UseCommas | X500DistinguishedNameFlags.UseNewLines | X500DistinguishedNameFlags.UseUTF8Encoding | X500DistinguishedNameFlags.UseT61Encoding | X500DistinguishedNameFlags.ForceUTF8Encoding)) == 0)
			{
				throw new ArgumentException("flag");
			}
			if (base.RawData.Length == 0)
			{
				return string.Empty;
			}
			bool flag2 = (flag & X500DistinguishedNameFlags.Reversed) != 0;
			bool flag3 = (flag & X500DistinguishedNameFlags.DoNotUseQuotes) == 0;
			string separator = GetSeparator(flag);
			return X501.ToString(new ASN1(base.RawData), flag2, separator, flag3);
		}

		public override string Format(bool multiLine)
		{
			if (multiLine)
			{
				string text = Decode(X500DistinguishedNameFlags.UseNewLines);
				if (text.Length > 0)
				{
					return text + Environment.NewLine;
				}
				return text;
			}
			return Decode(X500DistinguishedNameFlags.UseCommas);
		}

		private static string GetSeparator(X500DistinguishedNameFlags flag)
		{
			if ((flag & X500DistinguishedNameFlags.UseSemicolons) != X500DistinguishedNameFlags.None)
			{
				return "; ";
			}
			if ((flag & X500DistinguishedNameFlags.UseCommas) != X500DistinguishedNameFlags.None)
			{
				return ", ";
			}
			if ((flag & X500DistinguishedNameFlags.UseNewLines) != X500DistinguishedNameFlags.None)
			{
				return Environment.NewLine;
			}
			return ", ";
		}

		private void DecodeRawData()
		{
			if (base.RawData == null || base.RawData.Length < 3)
			{
				name = string.Empty;
				return;
			}
			ASN1 aSN = new ASN1(base.RawData);
			name = X501.ToString(aSN, reversed: true, ", ", quotes: true);
		}

		private static string Canonize(string s)
		{
			int i = s.IndexOf('=') + 1;
			StringBuilder stringBuilder = new StringBuilder(s.Substring(0, i));
			for (; i < s.Length && char.IsWhiteSpace(s, i); i++)
			{
			}
			s = s.TrimEnd();
			bool flag = false;
			for (; i < s.Length; i++)
			{
				if (flag)
				{
					flag = char.IsWhiteSpace(s, i);
					if (flag)
					{
						continue;
					}
				}
				if (char.IsWhiteSpace(s, i))
				{
					flag = true;
				}
				stringBuilder.Append(char.ToUpperInvariant(s[i]));
			}
			return stringBuilder.ToString();
		}

		internal static bool AreEqual(X500DistinguishedName name1, X500DistinguishedName name2)
		{
			if (name1 == null)
			{
				return name2 == null;
			}
			if (name2 == null)
			{
				return false;
			}
			if (name1.canonEncoding != null && name2.canonEncoding != null)
			{
				if (name1.canonEncoding.Length != name2.canonEncoding.Length)
				{
					return false;
				}
				for (int i = 0; i < name1.canonEncoding.Length; i++)
				{
					if (name1.canonEncoding[i] != name2.canonEncoding[i])
					{
						return false;
					}
				}
				return true;
			}
			X500DistinguishedNameFlags flag = X500DistinguishedNameFlags.DoNotUseQuotes | X500DistinguishedNameFlags.UseNewLines;
			string[] separator = new string[1] { Environment.NewLine };
			string[] array = name1.Decode(flag).Split(separator, StringSplitOptions.RemoveEmptyEntries);
			string[] array2 = name2.Decode(flag).Split(separator, StringSplitOptions.RemoveEmptyEntries);
			if (array.Length != array2.Length)
			{
				return false;
			}
			for (int j = 0; j < array.Length; j++)
			{
				if (Canonize(array[j]) != Canonize(array2[j]))
				{
					return false;
				}
			}
			return true;
		}
	}
	public sealed class X509BasicConstraintsExtension : X509Extension
	{
		private bool _certificateAuthority;

		private bool _hasPathLengthConstraint;

		private int _pathLengthConstraint;

		private AsnDecodeStatus _status;

		public bool CertificateAuthority
		{
			get
			{
				AsnDecodeStatus status = _status;
				if (status == AsnDecodeStatus.Ok || status == AsnDecodeStatus.InformationNotAvailable)
				{
					return _certificateAuthority;
				}
				throw new CryptographicException("Badly encoded extension.");
			}
		}

		public bool HasPathLengthConstraint
		{
			get
			{
				AsnDecodeStatus status = _status;
				if (status == AsnDecodeStatus.Ok || status == AsnDecodeStatus.InformationNotAvailable)
				{
					return _hasPathLengthConstraint;
				}
				throw new CryptographicException("Badly encoded extension.");
			}
		}

		public int PathLengthConstraint
		{
			get
			{
				AsnDecodeStatus status = _status;
				if (status == AsnDecodeStatus.Ok || status == AsnDecodeStatus.InformationNotAvailable)
				{
					return _pathLengthConstraint;
				}
				throw new CryptographicException("Badly encoded extension.");
			}
		}

		public X509BasicConstraintsExtension()
		{
			_oid = new Oid("2.5.29.19", "Basic Constraints");
		}

		public X509BasicConstraintsExtension(AsnEncodedData encodedBasicConstraints, bool critical)
		{
			_oid = new Oid("2.5.29.19", "Basic Constraints");
			_raw = encodedBasicConstraints.RawData;
			base.Critical = critical;
			_status = Decode(base.RawData);
		}

		public override void CopyFrom(AsnEncodedData asnEncodedData)
		{
			if (asnEncodedData == null)
			{
				throw new ArgumentNullException("asnEncodedData");
			}
			if (!(asnEncodedData is X509Extension x509Extension))
			{
				throw new ArgumentException(Locale.GetText("Wrong type."), "asnEncodedData");
			}
			if (x509Extension._oid == null)
			{
				_oid = new Oid("2.5.29.19", "Basic Constraints");
			}
			else
			{
				_oid = new Oid(x509Extension._oid);
			}
			base.RawData = x509Extension.RawData;
			base.Critical = x509Extension.Critical;
			_status = Decode(base.RawData);
		}

		internal AsnDecodeStatus Decode(byte[] extension)
		{
			if (extension == null || extension.Length == 0)
			{
				return AsnDecodeStatus.BadAsn;
			}
			if (extension[0] != 48)
			{
				return AsnDecodeStatus.BadTag;
			}
			if (extension.Length < 3 && (extension.Length != 2 || extension[1] != 0))
			{
				return AsnDecodeStatus.BadLength;
			}
			try
			{
				ASN1 aSN = new ASN1(extension);
				int num = 0;
				ASN1 aSN2 = aSN[num++];
				if (aSN2 != null && aSN2.Tag == 1)
				{
					_certificateAuthority = aSN2.Value[0] == 255;
					aSN2 = aSN[num++];
				}
				if (aSN2 != null && aSN2.Tag == 2)
				{
					_hasPathLengthConstraint = true;
					_pathLengthConstraint = ASN1Convert.ToInt32(aSN2);
				}
			}
			catch
			{
				return AsnDecodeStatus.BadAsn;
			}
			return AsnDecodeStatus.Ok;
		}

		internal override string ToString(bool multiLine)
		{
			switch (_status)
			{
			case AsnDecodeStatus.BadAsn:
				return string.Empty;
			case AsnDecodeStatus.BadTag:
			case AsnDecodeStatus.BadLength:
				return FormatUnkownData(_raw);
			case AsnDecodeStatus.InformationNotAvailable:
				return "Information Not Available";
			default:
			{
				if (_oid.Value != "2.5.29.19")
				{
					return $"Unknown Key Usage ({_oid.Value})";
				}
				StringBuilder stringBuilder = new StringBuilder();
				stringBuilder.Append("Subject Type=");
				if (_certificateAuthority)
				{
					stringBuilder.Append("CA");
				}
				else
				{
					stringBuilder.Append("End Entity");
				}
				if (multiLine)
				{
					stringBuilder.Append(Environment.NewLine);
				}
				else
				{
					stringBuilder.Append(", ");
				}
				stringBuilder.Append("Path Length Constraint=");
				if (_hasPathLengthConstraint)
				{
					stringBuilder.Append(_pathLengthConstraint);
				}
				else
				{
					stringBuilder.Append("None");
				}
				if (multiLine)
				{
					stringBuilder.Append(Environment.NewLine);
				}
				return stringBuilder.ToString();
			}
			}
		}
	}
	[Serializable]
	public class X509Certificate2 : X509Certificate
	{
		private volatile byte[] lazyRawData;

		private volatile Oid lazySignatureAlgorithm;

		private volatile int lazyVersion;

		private volatile X500DistinguishedName lazySubjectName;

		private volatile X500DistinguishedName lazyIssuerName;

		private volatile PublicKey lazyPublicKey;

		private volatile AsymmetricAlgorithm lazyPrivateKey;

		private volatile X509ExtensionCollection lazyExtensions;

		public X509ExtensionCollection Extensions
		{
			get
			{
				ThrowIfInvalid();
				X509ExtensionCollection x509ExtensionCollection = lazyExtensions;
				if (x509ExtensionCollection == null)
				{
					x509ExtensionCollection = new X509ExtensionCollection();
					foreach (X509Extension extension in Impl.Extensions)
					{
						X509Extension x509Extension = CreateCustomExtensionIfAny(extension.Oid);
						if (x509Extension == null)
						{
							x509ExtensionCollection.Add(extension);
							continue;
						}
						x509Extension.CopyFrom(extension);
						x509ExtensionCollection.Add(x509Extension);
					}
					lazyExtensions = x509ExtensionCollection;
				}
				return x509ExtensionCollection;
			}
		}

		public bool HasPrivateKey
		{
			get
			{
				ThrowIfInvalid();
				return Impl.HasPrivateKey;
			}
		}

		public AsymmetricAlgorithm PrivateKey
		{
			get
			{
				ThrowIfInvalid();
				if (!HasPrivateKey)
				{
					return null;
				}
				if (lazyPrivateKey == null)
				{
					string keyAlgorithm = GetKeyAlgorithm();
					if (!(keyAlgorithm == "1.2.840.113549.1.1.1"))
					{
						if (!(keyAlgorithm == "1.2.840.10040.4.1"))
						{
							throw new NotSupportedException("The certificate key algorithm is not supported.");
						}
						lazyPrivateKey = Impl.GetDSAPrivateKey();
					}
					else
					{
						lazyPrivateKey = Impl.GetRSAPrivateKey();
					}
				}
				return lazyPrivateKey;
			}
		}

		public X500DistinguishedName IssuerName
		{
			get
			{
				ThrowIfInvalid();
				X500DistinguishedName x500DistinguishedName = lazyIssuerName;
				if (x500DistinguishedName == null)
				{
					x500DistinguishedName = (lazyIssuerName = Impl.IssuerName);
				}
				return x500DistinguishedName;
			}
		}

		public DateTime NotAfter => GetNotAfter();

		public DateTime NotBefore => GetNotBefore();

		public PublicKey PublicKey
		{
			get
			{
				ThrowIfInvalid();
				PublicKey publicKey = lazyPublicKey;
				if (publicKey == null)
				{
					string keyAlgorithm = GetKeyAlgorithm();
					byte[] keyAlgorithmParameters = GetKeyAlgorithmParameters();
					byte[] publicKey2 = GetPublicKey();
					Oid oid = new Oid(keyAlgorithm);
					publicKey = (lazyPublicKey = new PublicKey(oid, new AsnEncodedData(oid, keyAlgorithmParameters), new AsnEncodedData(oid, publicKey2)));
				}
				return publicKey;
			}
		}

		public byte[] RawData
		{
			get
			{
				ThrowIfInvalid();
				byte[] array = lazyRawData;
				if (array == null)
				{
					array = (lazyRawData = Impl.RawData);
				}
				return array.CloneByteArray();
			}
		}

		public string SerialNumber => GetSerialNumberString();

		public Oid SignatureAlgorithm
		{
			get
			{
				ThrowIfInvalid();
				Oid oid = lazySignatureAlgorithm;
				if (oid == null)
				{
					string signatureAlgorithm = Impl.SignatureAlgorithm;
					oid = (lazySignatureAlgorithm = Oid.FromOidValue(signatureAlgorithm, OidGroup.SignatureAlgorithm));
				}
				return oid;
			}
