			case "2.5.29.15":
				return new X509KeyUsageExtension();
			case "2.5.29.37":
				return new X509EnhancedKeyUsageExtension();
			case "2.5.29.14":
				return new X509SubjectKeyIdentifierExtension();
			default:
				return null;
