	internal static class X509Helper2
	{
		internal static Mono.Security.X509.X509Certificate GetMonoCertificate(X509Certificate2 certificate)
		{
			if (certificate.Impl is X509Certificate2ImplMono x509Certificate2ImplMono)
			{
				return x509Certificate2ImplMono.MonoCertificate;
			}
			return new Mono.Security.X509.X509Certificate(certificate.RawData);
		}

		internal static X509ChainImpl CreateChainImpl(bool useMachineContext)
		{
			return new X509ChainImplMono(useMachineContext);
		}

		public static bool IsValid(X509ChainImpl impl)
		{
			return impl?.IsValid ?? false;
		}

		internal static void ThrowIfContextInvalid(X509ChainImpl impl)
		{
			if (!IsValid(impl))
			{
				throw GetInvalidChainContextException();
			}
		}

		internal static Exception GetInvalidChainContextException()
		{
			return new CryptographicException(Locale.GetText("Chain instance is empty."));
		}
	}
	public sealed class X509KeyUsageExtension : X509Extension
	{
		private X509KeyUsageFlags _keyUsages;

		private AsnDecodeStatus _status;

		public X509KeyUsageFlags KeyUsages
		{
			get
			{
				AsnDecodeStatus status = _status;
				if (status == AsnDecodeStatus.Ok || status == AsnDecodeStatus.InformationNotAvailable)
				{
					return _keyUsages;
				}
				throw new CryptographicException("Badly encoded extension.");
			}
		}

		public X509KeyUsageExtension()
		{
			_oid = new Oid("2.5.29.15", "Key Usage");
		}

		public X509KeyUsageExtension(AsnEncodedData encodedKeyUsage, bool critical)
		{
			_oid = new Oid("2.5.29.15", "Key Usage");
			_raw = encodedKeyUsage.RawData;
			base.Critical = critical;
			_status = Decode(base.RawData);
		}

		public override void CopyFrom(AsnEncodedData asnEncodedData)
		{
			if (asnEncodedData == null)
			{
				throw new ArgumentNullException("asnEncodedData");
			}
			if (!(asnEncodedData is X509Extension x509Extension))
			{
				throw new ArgumentException(Locale.GetText("Wrong type."), "asnEncodedData");
			}
			if (x509Extension._oid == null)
			{
				_oid = new Oid("2.5.29.15", "Key Usage");
			}
			else
			{
				_oid = new Oid(x509Extension._oid);
			}
			base.RawData = x509Extension.RawData;
			base.Critical = x509Extension.Critical;
			_status = Decode(base.RawData);
		}

		internal X509KeyUsageFlags GetValidFlags(X509KeyUsageFlags flags)
		{
			if ((flags & (X509KeyUsageFlags.EncipherOnly | X509KeyUsageFlags.CrlSign | X509KeyUsageFlags.KeyCertSign | X509KeyUsageFlags.KeyAgreement | X509KeyUsageFlags.DataEncipherment | X509KeyUsageFlags.KeyEncipherment | X509KeyUsageFlags.NonRepudiation | X509KeyUsageFlags.DigitalSignature | X509KeyUsageFlags.DecipherOnly)) != flags)
			{
				return X509KeyUsageFlags.None;
			}
			return flags;
		}

		internal AsnDecodeStatus Decode(byte[] extension)
		{
			if (extension == null || extension.Length == 0)
			{
				return AsnDecodeStatus.BadAsn;
			}
			if (extension[0] != 3)
			{
				return AsnDecodeStatus.BadTag;
			}
			if (extension.Length < 3)
			{
				return AsnDecodeStatus.BadLength;
			}
			if (extension.Length < 4)
			{
				return AsnDecodeStatus.InformationNotAvailable;
			}
			try
			{
				ASN1 aSN = new ASN1(extension);
				int num = 0;
				int num2 = 1;
				while (num2 < aSN.Value.Length)
				{
					num = (num << 8) + aSN.Value[num2++];
				}
				_keyUsages = GetValidFlags((X509KeyUsageFlags)num);
			}
			catch
			{
				return AsnDecodeStatus.BadAsn;
			}
			return AsnDecodeStatus.Ok;
		}

		internal override string ToString(bool multiLine)
		{
			switch (_status)
			{
			case AsnDecodeStatus.BadAsn:
				return string.Empty;
			case AsnDecodeStatus.BadTag:
			case AsnDecodeStatus.BadLength:
				return FormatUnkownData(_raw);
			case AsnDecodeStatus.InformationNotAvailable:
				return "Information Not Available";
			default:
			{
				if (_oid.Value != "2.5.29.15")
				{
					return $"Unknown Key Usage ({_oid.Value})";
				}
				if (_keyUsages == X509KeyUsageFlags.None)
				{
					return "Information Not Available";
				}
				StringBuilder stringBuilder = new StringBuilder();
				if ((_keyUsages & X509KeyUsageFlags.DigitalSignature) != X509KeyUsageFlags.None)
				{
					stringBuilder.Append("Digital Signature");
				}
				if ((_keyUsages & X509KeyUsageFlags.NonRepudiation) != X509KeyUsageFlags.None)
				{
					if (stringBuilder.Length > 0)
					{
						stringBuilder.Append(", ");
					}
					stringBuilder.Append("Non-Repudiation");
				}
				if ((_keyUsages & X509KeyUsageFlags.KeyEncipherment) != X509KeyUsageFlags.None)
				{
					if (stringBuilder.Length > 0)
					{
						stringBuilder.Append(", ");
					}
					stringBuilder.Append("Key Encipherment");
				}
				if ((_keyUsages & X509KeyUsageFlags.DataEncipherment) != X509KeyUsageFlags.None)
				{
					if (stringBuilder.Length > 0)
					{
						stringBuilder.Append(", ");
					}
					stringBuilder.Append("Data Encipherment");
				}
				if ((_keyUsages & X509KeyUsageFlags.KeyAgreement) != X509KeyUsageFlags.None)
				{
					if (stringBuilder.Length > 0)
					{
						stringBuilder.Append(", ");
					}
					stringBuilder.Append("Key Agreement");
				}
				if ((_keyUsages & X509KeyUsageFlags.KeyCertSign) != X509KeyUsageFlags.None)
				{
					if (stringBuilder.Length > 0)
					{
						stringBuilder.Append(", ");
					}
					stringBuilder.Append("Certificate Signing");
				}
				if ((_keyUsages & X509KeyUsageFlags.CrlSign) != X509KeyUsageFlags.None)
				{
					if (stringBuilder.Length > 0)
					{
						stringBuilder.Append(", ");
					}
					stringBuilder.Append("Off-line CRL Signing, CRL Signing");
				}
				if ((_keyUsages & X509KeyUsageFlags.EncipherOnly) != X509KeyUsageFlags.None)
				{
					if (stringBuilder.Length > 0)
					{
						stringBuilder.Append(", ");
					}
					stringBuilder.Append("Encipher Only");
				}
				if ((_keyUsages & X509KeyUsageFlags.DecipherOnly) != X509KeyUsageFlags.None)
				{
					if (stringBuilder.Length > 0)
					{
						stringBuilder.Append(", ");
					}
					stringBuilder.Append("Decipher Only");
				}
				int keyUsages = (int)_keyUsages;
				stringBuilder.Append(" (");
				stringBuilder.Append(((byte)keyUsages).ToString("x2"));
				if (keyUsages > 255)
				{
					stringBuilder.Append(" ");
					stringBuilder.Append(((byte)(keyUsages >> 8)).ToString("x2"));
				}
				stringBuilder.Append(")");
				if (multiLine)
				{
					stringBuilder.Append(Environment.NewLine);
				}
				return stringBuilder.ToString();
			}
			}
		}
	}
	public sealed class X509Store : IDisposable
	{
		private string _name;

		private StoreLocation _location;

		private X509Certificate2Collection list;

		private OpenFlags _flags;

		private Mono.Security.X509.X509Store store;

		public X509Certificate2Collection Certificates
		{
			get
			{
				if (list == null)
				{
					list = new X509Certificate2Collection();
				}
				else if (store == null)
				{
					list.Clear();
				}
				return list;
			}
		}

		private X509Stores Factory
		{
			get
			{
				if (_location == StoreLocation.CurrentUser)
				{
					return X509StoreManager.CurrentUser;
				}
				return X509StoreManager.LocalMachine;
			}
		}

		internal Mono.Security.X509.X509Store Store => store;

		public X509Store(StoreName storeName, StoreLocation storeLocation)
		{
			if (storeName < StoreName.AddressBook || storeName > StoreName.TrustedPublisher)
			{
				throw new ArgumentException("storeName");
			}
			if (storeLocation < StoreLocation.CurrentUser || storeLocation > StoreLocation.LocalMachine)
			{
				throw new ArgumentException("storeLocation");
			}
			if (storeName == StoreName.CertificateAuthority)
			{
				_name = "CA";
			}
			else
			{
				_name = storeName.ToString();
			}
			_location = storeLocation;
		}

		public void Close()
		{
			store = null;
			if (list != null)
			{
				list.Clear();
			}
		}

		public void Dispose()
		{
			Close();
		}

		public void Open(OpenFlags flags)
		{
			if (string.IsNullOrEmpty(_name))
			{
				throw new CryptographicException(Locale.GetText("Invalid store name (null or empty)."));
			}
			string storeName = ((!(_name == "Root")) ? _name : "Trust");
			bool create = (flags & OpenFlags.OpenExistingOnly) != OpenFlags.OpenExistingOnly;
			store = Factory.Open(storeName, create);
			if (store == null)
			{
				throw new CryptographicException(Locale.GetText("Store {0} doesn't exists.", _name));
			}
			_flags = flags;
			foreach (Mono.Security.X509.X509Certificate certificate in store.Certificates)
			{
				X509Certificate2 x509Certificate = new X509Certificate2(certificate.RawData);
				x509Certificate.Impl.PrivateKey = certificate.RSA;
				Certificates.Add(x509Certificate);
			}
		}
	}
	public sealed class X509SubjectKeyIdentifierExtension : X509Extension
	{
		private byte[] _subjectKeyIdentifier;

		private string _ski;

		private AsnDecodeStatus _status;

		public string SubjectKeyIdentifier
		{
			get
			{
				AsnDecodeStatus status = _status;
				if (status == AsnDecodeStatus.Ok || status == AsnDecodeStatus.InformationNotAvailable)
				{
					if (_subjectKeyIdentifier != null)
					{
						_ski = CryptoConvert.ToHex(_subjectKeyIdentifier);
					}
					return _ski;
				}
				throw new CryptographicException("Badly encoded extension.");
			}
		}

		public X509SubjectKeyIdentifierExtension()
		{
			_oid = new Oid("2.5.29.14", "Subject Key Identifier");
		}

		public X509SubjectKeyIdentifierExtension(AsnEncodedData encodedSubjectKeyIdentifier, bool critical)
		{
			_oid = new Oid("2.5.29.14", "Subject Key Identifier");
			_raw = encodedSubjectKeyIdentifier.RawData;
			base.Critical = critical;
			_status = Decode(base.RawData);
		}

		public X509SubjectKeyIdentifierExtension(PublicKey key, X509SubjectKeyIdentifierHashAlgorithm algorithm, bool critical)
		{
			if (key == null)
			{
				throw new ArgumentNullException("key");
			}
			byte[] rawData = key.EncodedKeyValue.RawData;
			switch (algorithm)
			{
			case X509SubjectKeyIdentifierHashAlgorithm.Sha1:
				_subjectKeyIdentifier = SHA1.Create().ComputeHash(rawData);
				break;
			case X509SubjectKeyIdentifierHashAlgorithm.ShortSha1:
			{
				byte[] src = SHA1.Create().ComputeHash(rawData);
				_subjectKeyIdentifier = new byte[8];
				Buffer.BlockCopy(src, 12, _subjectKeyIdentifier, 0, 8);
				_subjectKeyIdentifier[0] = (byte)(0x40 | (_subjectKeyIdentifier[0] & 0xF));
				break;
			}
			case X509SubjectKeyIdentifierHashAlgorithm.CapiSha1:
			{
				ASN1 aSN = new ASN1(48);
				ASN1 aSN2 = aSN.Add(new ASN1(48));
				aSN2.Add(new ASN1(CryptoConfig.EncodeOID(key.Oid.Value)));
				aSN2.Add(new ASN1(key.EncodedParameters.RawData));
				byte[] array = new byte[rawData.Length + 1];
				Buffer.BlockCopy(rawData, 0, array, 1, rawData.Length);
				aSN.Add(new ASN1(3, array));
				_subjectKeyIdentifier = SHA1.Create().ComputeHash(aSN.GetBytes());
				break;
			}
			default:
				throw new ArgumentException("algorithm");
			}
			_oid = new Oid("2.5.29.14", "Subject Key Identifier");
			base.Critical = critical;
			base.RawData = Encode();
		}

		public override void CopyFrom(AsnEncodedData asnEncodedData)
		{
			if (asnEncodedData == null)
			{
				throw new ArgumentNullException("asnEncodedData");
			}
			if (!(asnEncodedData is X509Extension x509Extension))
			{
				throw new ArgumentException(Locale.GetText("Wrong type."), "asnEncodedData");
			}
			if (x509Extension._oid == null)
			{
				_oid = new Oid("2.5.29.14", "Subject Key Identifier");
			}
			else
			{
				_oid = new Oid(x509Extension._oid);
			}
			base.RawData = x509Extension.RawData;
			base.Critical = x509Extension.Critical;
			_status = Decode(base.RawData);
		}

		internal AsnDecodeStatus Decode(byte[] extension)
		{
			if (extension == null || extension.Length == 0)
			{
				return AsnDecodeStatus.BadAsn;
			}
			_ski = string.Empty;
			if (extension[0] != 4)
			{
				return AsnDecodeStatus.BadTag;
			}
			if (extension.Length == 2)
			{
				return AsnDecodeStatus.InformationNotAvailable;
			}
			if (extension.Length < 3)
			{
				return AsnDecodeStatus.BadLength;
			}
			try
			{
				ASN1 aSN = new ASN1(extension);
				_subjectKeyIdentifier = aSN.Value;
			}
			catch
			{
				return AsnDecodeStatus.BadAsn;
			}
			return AsnDecodeStatus.Ok;
		}

		internal byte[] Encode()
		{
			return new ASN1(4, _subjectKeyIdentifier).GetBytes();
		}

		internal override string ToString(bool multiLine)
		{
			switch (_status)
			{
			case AsnDecodeStatus.BadAsn:
				return string.Empty;
			case AsnDecodeStatus.BadTag:
			case AsnDecodeStatus.BadLength:
				return FormatUnkownData(_raw);
			case AsnDecodeStatus.InformationNotAvailable:
				return "Information Not Available";
			default:
			{
				if (_oid.Value != "2.5.29.14")
				{
					return $"Unknown Key Usage ({_oid.Value})";
				}
				StringBuilder stringBuilder = new StringBuilder();
				for (int i = 0; i < _subjectKeyIdentifier.Length; i++)
				{
					stringBuilder.Append(_subjectKeyIdentifier[i].ToString("x2"));
					if (i != _subjectKeyIdentifier.Length - 1)
					{
						stringBuilder.Append(" ");
					}
				}
				if (multiLine)
				{
					stringBuilder.Append(Environment.NewLine);
				}
				return stringBuilder.ToString();
			}
			}
		}
	}
