			}
			if (arg3 == null)
			{
				arg3 = "";
			}
			if (arg4 == null)
			{
				arg4 = "";
			}
			fixed (char* ptr = arg1)
			{
				fixed (char* ptr2 = arg2)
				{
					fixed (char* ptr3 = arg3)
					{
						fixed (char* ptr4 = arg4)
						{
							EventData* ptr5 = stackalloc EventData[4];
							*ptr5 = new EventData
