	{
		public static string[] EmptyArray = new string[0];

		internal static readonly char[] InvalidMethodChars = new char[4] { ' ', '\r', '\n', '\t' };

		internal static readonly char[] InvalidParamChars = new char[22]
		{
			'(', ')', '<', '>', '@', ',', ';', ':', '\\', '"',
			'\'', '/', '[', ']', '?', '=', '{', '}', ' ', '\t',
			'\r', '\n'
