		}

		public unsafe static void HtmlEncode(string value, TextWriter output)
		{
			if (value == null)
			{
				return;
			}
			if (output == null)
			{
				throw new ArgumentNullException("output");
			}
			int num = IndexOfHtmlEncodingChars(value, 0);
			if (num == -1)
			{
				output.Write(value);
				return;
			}
			UnicodeEncodingConformance htmlEncodeConformance = HtmlEncodeConformance;
			int charsRemaining = value.Length - num;
			fixed (char* ptr = value)
			{
				char* pch = ptr;
				while (num-- > 0)
				{
					output.Write(*(pch++));
				}
				while (charsRemaining > 0)
				{
					char c = *pch;
					if (c <= '>')
					{
						switch (c)
						{
						case '<':
							output.Write("&lt;");
							break;
						case '>':
							output.Write("&gt;");
							break;
						case '"':
							output.Write("&quot;");
							break;
						case '\'':
							output.Write("&#39;");
							break;
						case '&':
							output.Write("&amp;");
							break;
						default:
							output.Write(c);
							break;
						}
					}
					else
					{
						int num2 = -1;
						if (c >= '\u00a0' && !char.IsSurrogate(c))
						{
							num2 = c;
						}
