				{
					return bytes;
				}
				byte[] array = new byte[count];
				Buffer.BlockCopy(bytes, offset, array, 0, count);
				return array;
			}
			byte[] array2 = new byte[count + num2 * 2];
			int num3 = 0;
			for (int j = 0; j < count; j++)
			{
				byte b = bytes[offset + j];
				char c2 = (char)b;
				if (IsUrlSafeChar(c2))
