			for (int i = 0; i < length; i++)
			{
				char c = value[i];
				switch (c)
				{
				case '+':
					c = ' ';
					break;
				case '%':
					if (i < length - 2)
					{
						int num = HexToInt(value[i + 1]);
						int num2 = HexToInt(value[i + 2]);
						if (num >= 0 && num2 >= 0)
						{
							byte b = (byte)((num << 4) | num2);
							i += 2;
							urlDecoder.AddByte(b);
							continue;
						}
					}
					break;
				}
				if ((c & 0xFF80) == 0)
				{
					urlDecoder.AddByte((byte)c);
				}
				else
				{
					urlDecoder.AddChar(c);
				}
			}
			return urlDecoder.GetString();
		}

		public static string UrlDecode(string encodedValue)
		{
			if (encodedValue == null)
			{
				return null;
			}
			return UrlDecodeInternal(encodedValue, Encoding.UTF8);
		}

		private unsafe static int GetNextUnicodeScalarValueFromUtf16Surrogate(ref char* pch, ref int charsRemaining)
		{
			if (charsRemaining <= 1)
			{
				return 65533;
			}
			char c = *pch;
			char c2 = pch[1];
			if (char.IsSurrogatePair(c, c2))
			{
				pch++;
				charsRemaining--;
				return (c - 55296) * 1024 + (c2 - 56320) + 65536;
			}
			return 65533;
		}

		private static int HexToInt(char h)
		{
			if (h < '0' || h > '9')
			{
				if (h < 'a' || h > 'f')
				{
					if (h < 'A' || h > 'F')
					{
						return -1;
					}
					return h - 65 + 10;
				}
				return h - 97 + 10;
			}
			return h - 48;
		}

		private static char IntToHex(int n)
		{
			if (n <= 9)
			{
				return (char)(n + 48);
			}
			return (char)(n - 10 + 65);
		}

		private static bool IsUrlSafeChar(char ch)
		{
			if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z') || (ch >= '0' && ch <= '9'))
			{
				return true;
			}
			switch (ch)
			{
			case '!':
			case '(':
			case ')':
			case '*':
			case '-':
			case '.':
			case '_':
				return true;
			default:
				return false;
			}
		}

		private static bool ValidateUrlEncodingParameters(byte[] bytes, int offset, int count)
		{
			if (bytes == null && count == 0)
			{
				return false;
			}
			if (bytes == null)
			{
				throw new ArgumentNullException("bytes");
			}
			if (offset < 0 || offset > bytes.Length)
			{
				throw new ArgumentOutOfRangeException("offset");
			}
			if (count < 0 || offset + count > bytes.Length)
			{
				throw new ArgumentOutOfRangeException("count");
			}
			return true;
		}
	}
