			}

			internal override bool Cancel()
			{
				if (m_TimerState == TimerState.Ready)
				{
					lock (m_QueueLock)
					{
						if (m_TimerState == TimerState.Ready)
						{
							Next.Prev = Prev;
							Prev.Next = Next;
							Next = null;
							Prev = null;
							m_Callback = null;
							m_Context = null;
							m_TimerState = TimerState.Cancelled;
							return true;
						}
					}
				}
				return false;
			}

			internal bool Fire()
			{
