		private static bool DomainCharsTest(string name)
		{
			if (name == null || name.Length == 0)
			{
				return false;
			}
			foreach (char c in name)
			{
				if (c >= '0' && c <= '9')
				{
					continue;
				}
				switch (c)
				{
				case '-':
				case '.':
				case 'a':
				case 'b':
				case 'c':
				case 'd':
				case 'e':
				case 'f':
				case 'g':
				case 'h':
				case 'i':
				case 'j':
				case 'k':
				case 'l':
				case 'm':
				case 'n':
				case 'o':
				case 'p':
				case 'q':
				case 'r':
				case 's':
				case 't':
				case 'u':
				case 'v':
				case 'w':
				case 'x':
				case 'y':
				case 'z':
					continue;
				}
				if ((c < 'A' || c > 'Z') && c != '_')
				{
					return false;
				}
			}
			return true;
		}

		internal static IComparer GetComparer()
		{
