	internal class ServerCertValidationCallback
	{
		private class CallbackContext
		{
			internal readonly object request;

			internal readonly System.Security.Cryptography.X509Certificates.X509Certificate certificate;

			internal readonly System.Security.Cryptography.X509Certificates.X509Chain chain;

			internal readonly SslPolicyErrors sslPolicyErrors;

			internal bool result;

			internal CallbackContext(object request, System.Security.Cryptography.X509Certificates.X509Certificate certificate, System.Security.Cryptography.X509Certificates.X509Chain chain, SslPolicyErrors sslPolicyErrors)
			{
				this.request = request;
				this.certificate = certificate;
				this.chain = chain;
				this.sslPolicyErrors = sslPolicyErrors;
			}
		}

		private readonly RemoteCertificateValidationCallback m_ValidationCallback;

		private readonly ExecutionContext m_Context;

		internal RemoteCertificateValidationCallback ValidationCallback => m_ValidationCallback;

		internal ServerCertValidationCallback(RemoteCertificateValidationCallback validationCallback)
		{
			m_ValidationCallback = validationCallback;
			m_Context = ExecutionContext.Capture();
		}

		internal void Callback(object state)
		{
			CallbackContext callbackContext = (CallbackContext)state;
			callbackContext.result = m_ValidationCallback(callbackContext.request, callbackContext.certificate, callbackContext.chain, callbackContext.sslPolicyErrors);
		}

		internal bool Invoke(object request, System.Security.Cryptography.X509Certificates.X509Certificate certificate, System.Security.Cryptography.X509Certificates.X509Chain chain, SslPolicyErrors sslPolicyErrors)
		{
			if (m_Context == null)
			{
				return m_ValidationCallback(request, certificate, chain, sslPolicyErrors);
			}
			ExecutionContext executionContext = m_Context.CreateCopy();
			CallbackContext callbackContext = new CallbackContext(request, certificate, chain, sslPolicyErrors);
			ExecutionContext.Run(executionContext, Callback, callbackContext);
			return callbackContext.result;
		}
	}
	public class AuthenticationManager
	{
		private static ArrayList modules;

		private static object locker = new object();

		private static ICredentialPolicy credential_policy = null;

		private static void EnsureModules()
		{
			lock (locker)
			{
				if (modules == null)
				{
					modules = new ArrayList();
					modules.Add(new NtlmClient());
					modules.Add(new DigestClient());
					modules.Add(new BasicClient());
				}
			}
		}

		public static Authorization Authenticate(string challenge, WebRequest request, ICredentials credentials)
		{
			if (request == null)
			{
				throw new ArgumentNullException("request");
			}
			if (credentials == null)
			{
				throw new ArgumentNullException("credentials");
			}
			if (challenge == null)
			{
				throw new ArgumentNullException("challenge");
			}
			return DoAuthenticate(challenge, request, credentials);
		}

		private static Authorization DoAuthenticate(string challenge, WebRequest request, ICredentials credentials)
		{
			EnsureModules();
			lock (modules)
			{
				foreach (IAuthenticationModule module in modules)
				{
					Authorization authorization = module.Authenticate(challenge, request, credentials);
					if (authorization != null)
					{
						authorization.ModuleAuthenticationType = module.AuthenticationType;
						return authorization;
					}
				}
			}
			return null;
		}

		public static Authorization PreAuthenticate(WebRequest request, ICredentials credentials)
		{
			if (request == null)
			{
				throw new ArgumentNullException("request");
			}
			if (credentials == null)
			{
				return null;
			}
			EnsureModules();
			lock (modules)
			{
				foreach (IAuthenticationModule module in modules)
				{
					Authorization authorization = module.PreAuthenticate(request, credentials);
					if (authorization != null)
					{
						authorization.ModuleAuthenticationType = module.AuthenticationType;
						return authorization;
					}
				}
			}
			return null;
		}
	}
	internal class BasicClient : IAuthenticationModule
	{
		public string AuthenticationType => "Basic";

		public Authorization Authenticate(string challenge, WebRequest webRequest, ICredentials credentials)
		{
			if (credentials == null || challenge == null)
			{
				return null;
			}
			if (challenge.Trim().ToLower().IndexOf("basic", StringComparison.Ordinal) == -1)
			{
				return null;
			}
			return InternalAuthenticate(webRequest, credentials);
		}

		private static byte[] GetBytes(string str)
		{
			int length = str.Length;
			byte[] array = new byte[length];
			for (length--; length >= 0; length--)
			{
				array[length] = (byte)str[length];
			}
			return array;
		}

		private static Authorization InternalAuthenticate(WebRequest webRequest, ICredentials credentials)
		{
			if (!(webRequest is HttpWebRequest httpWebRequest) || credentials == null)
			{
				return null;
			}
			NetworkCredential credential = credentials.GetCredential(httpWebRequest.AuthUri, "basic");
			if (credential == null)
			{
				return null;
			}
			string userName = credential.UserName;
			if (userName == null || userName == "")
			{
				return null;
			}
			string password = credential.Password;
			string domain = credential.Domain;
			byte[] inArray = ((domain != null && !(domain == "") && !(domain.Trim() == "")) ? GetBytes(domain + "\\" + userName + ":" + password) : GetBytes(userName + ":" + password));
