	internal class DigestHeaderParser
	{
		private string header;

		private int length;

		private int pos;

		private static string[] keywords = new string[5] { "realm", "opaque", "nonce", "algorithm", "qop" };

		private string[] values = new string[keywords.Length];

		public string Realm => values[0];

		public string Opaque => values[1];

		public string Nonce => values[2];

		public string Algorithm => values[3];

		public string QOP => values[4];

		public DigestHeaderParser(string header)
		{
			this.header = header.Trim();
		}

		public bool Parse()
		{
			if (!header.ToLower().StartsWith("digest "))
			{
				return false;
			}
			pos = 6;
			length = header.Length;
			while (pos < length)
			{
				if (!GetKeywordAndValue(out var key, out var value))
				{
					return false;
				}
				SkipWhitespace();
				if (pos < length && header[pos] == ',')
				{
					pos++;
				}
				int num = Array.IndexOf(keywords, key);
				if (num != -1)
				{
					if (values[num] != null)
					{
						return false;
					}
					values[num] = value;
				}
			}
			if (Realm == null || Nonce == null)
			{
				return false;
			}
			return true;
		}

		private void SkipWhitespace()
		{
			char c = ' ';
			while (pos < length && (c == ' ' || c == '\t' || c == '\r' || c == '\n'))
			{
				c = header[pos++];
			}
			pos--;
		}

		private string GetKey()
		{
			SkipWhitespace();
			int num = pos;
			while (pos < length && header[pos] != '=')
			{
				pos++;
			}
			return header.Substring(num, pos - num).Trim().ToLower();
		}

		private bool GetKeywordAndValue(out string key, out string value)
		{
			key = null;
			value = null;
			key = GetKey();
			if (pos >= length)
			{
				return false;
			}
			SkipWhitespace();
			if (pos + 1 >= length || header[pos++] != '=')
			{
				return false;
			}
			SkipWhitespace();
			if (pos + 1 >= length)
			{
				return false;
			}
			bool flag = false;
			if (header[pos] == '"')
			{
				pos++;
				flag = true;
			}
			int num = pos;
			if (flag)
			{
				pos = header.IndexOf('"', pos);
				if (pos == -1)
				{
					return false;
				}
			}
			else
			{
				char c;
				do
				{
					c = header[pos];
				}
				while (c != ',' && c != ' ' && c != '\t' && c != '\r' && c != '\n' && ++pos < length);
				if (pos >= length && num == pos)
				{
					return false;
				}
			}
			value = header.Substring(num, pos - num);
			pos += ((!flag) ? 1 : 2);
			return true;
		}
	}
	internal class DigestSession
	{
		private static RandomNumberGenerator rng;

		private DateTime lastUse;

		private int _nc;

		private HashAlgorithm hash;

		private DigestHeaderParser parser;

		private string _cnonce;

		public string Algorithm => parser.Algorithm;

		public string Realm => parser.Realm;

		public string Nonce => parser.Nonce;

		public string Opaque => parser.Opaque;

		public string QOP => parser.QOP;

		public string CNonce
		{
			get
			{
				if (_cnonce == null)
				{
					byte[] array = new byte[15];
					rng.GetBytes(array);
					_cnonce = Convert.ToBase64String(array);
					Array.Clear(array, 0, array.Length);
				}
				return _cnonce;
			}
		}

		public DateTime LastUse => lastUse;

		static DigestSession()
		{
			rng = RandomNumberGenerator.Create();
		}

		public DigestSession()
		{
			_nc = 1;
			lastUse = DateTime.UtcNow;
		}

		public bool Parse(string challenge)
		{
			parser = new DigestHeaderParser(challenge);
			if (!parser.Parse())
			{
				return false;
			}
			if (parser.Algorithm == null || parser.Algorithm.ToUpper().StartsWith("MD5"))
			{
				hash = MD5.Create();
			}
			return true;
		}

		private string HashToHexString(string toBeHashed)
		{
			if (hash == null)
			{
				return null;
			}
			hash.Initialize();
			byte[] array = hash.ComputeHash(Encoding.ASCII.GetBytes(toBeHashed));
			StringBuilder stringBuilder = new StringBuilder();
			byte[] array2 = array;
			foreach (byte b in array2)
			{
				stringBuilder.Append(b.ToString("x2"));
			}
			return stringBuilder.ToString();
		}

		private string HA1(string username, string password)
		{
			string toBeHashed = $"{username}:{Realm}:{password}";
			if (Algorithm != null && Algorithm.ToLower() == "md5-sess")
			{
				toBeHashed = $"{HashToHexString(toBeHashed)}:{Nonce}:{CNonce}";
			}
			return HashToHexString(toBeHashed);
		}

		private string HA2(HttpWebRequest webRequest)
		{
			string toBeHashed = $"{webRequest.Method}:{webRequest.RequestUri.PathAndQuery}";
			_ = QOP == "auth-int";
			return HashToHexString(toBeHashed);
		}

		private string Response(string username, string password, HttpWebRequest webRequest)
		{
			string text = $"{HA1(username, password)}:{Nonce}:";
			if (QOP != null)
			{
				text += string.Format("{0}:{1}:{2}:", _nc.ToString("X8"), CNonce, QOP);
			}
			text += HA2(webRequest);
			return HashToHexString(text);
		}

		public Authorization Authenticate(WebRequest webRequest, ICredentials credentials)
		{
			if (parser == null)
			{
				throw new InvalidOperationException();
			}
			if (!(webRequest is HttpWebRequest httpWebRequest))
			{
				return null;
			}
			lastUse = DateTime.UtcNow;
			NetworkCredential credential = credentials.GetCredential(httpWebRequest.RequestUri, "digest");
			if (credential == null)
			{
				return null;
			}
			string userName = credential.UserName;
			if (userName == null || userName == "")
			{
				return null;
			}
			string password = credential.Password;
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.AppendFormat("Digest username=\"{0}\", ", userName);
			stringBuilder.AppendFormat("realm=\"{0}\", ", Realm);
			stringBuilder.AppendFormat("nonce=\"{0}\", ", Nonce);
			stringBuilder.AppendFormat("uri=\"{0}\", ", httpWebRequest.Address.PathAndQuery);
			if (Algorithm != null)
			{
				stringBuilder.AppendFormat("algorithm=\"{0}\", ", Algorithm);
			}
			stringBuilder.AppendFormat("response=\"{0}\", ", Response(userName, password, httpWebRequest));
			if (QOP != null)
			{
				stringBuilder.AppendFormat("qop=\"{0}\", ", QOP);
			}
			lock (this)
			{
				if (QOP != null)
				{
					stringBuilder.AppendFormat("nc={0:X8}, ", _nc);
					_nc++;
				}
			}
			if (CNonce != null)
			{
				stringBuilder.AppendFormat("cnonce=\"{0}\", ", CNonce);
			}
			if (Opaque != null)
			{
				stringBuilder.AppendFormat("opaque=\"{0}\", ", Opaque);
			}
			stringBuilder.Length -= 2;
			return new Authorization(stringBuilder.ToString());
		}
	}
	internal class DigestClient : IAuthenticationModule
	{
		private static readonly Hashtable cache = Hashtable.Synchronized(new Hashtable());

		private static Hashtable Cache
		{
			get
			{
				lock (cache.SyncRoot)
				{
					CheckExpired(cache.Count);
				}
				return cache;
			}
		}

		public string AuthenticationType => "Digest";

		private static void CheckExpired(int count)
		{
			if (count < 10)
			{
				return;
			}
			DateTime dateTime = DateTime.MaxValue;
			DateTime utcNow = DateTime.UtcNow;
			ArrayList arrayList = null;
			foreach (int key in cache.Keys)
			{
				DigestSession digestSession = (DigestSession)cache[key];
				if (digestSession.LastUse < dateTime && (digestSession.LastUse - utcNow).Ticks > 6000000000L)
				{
					dateTime = digestSession.LastUse;
					if (arrayList == null)
					{
						arrayList = new ArrayList();
					}
					arrayList.Add(key);
				}
			}
			if (arrayList == null)
			{
				return;
			}
			foreach (int item in arrayList)
			{
				cache.Remove(item);
			}
		}

		public Authorization Authenticate(string challenge, WebRequest webRequest, ICredentials credentials)
		{
			if (credentials == null || challenge == null)
			{
				return null;
			}
			if (challenge.Trim().ToLower().IndexOf("digest") == -1)
			{
				return null;
			}
			if (!(webRequest is HttpWebRequest httpWebRequest))
			{
				return null;
			}
			DigestSession digestSession = new DigestSession();
			if (!digestSession.Parse(challenge))
			{
				return null;
			}
			int num = httpWebRequest.Address.GetHashCode() ^ credentials.GetHashCode() ^ digestSession.Nonce.GetHashCode();
			DigestSession digestSession2 = (DigestSession)Cache[num];
			bool flag = digestSession2 == null;
			if (flag)
			{
				digestSession2 = digestSession;
			}
			else if (!digestSession2.Parse(challenge))
			{
				return null;
			}
			if (flag)
			{
				Cache.Add(num, digestSession2);
			}
			return digestSession2.Authenticate(webRequest, credentials);
		}

		public Authorization PreAuthenticate(WebRequest webRequest, ICredentials credentials)
		{
			if (!(webRequest is HttpWebRequest httpWebRequest))
			{
				return null;
			}
			if (credentials == null)
			{
				return null;
			}
			int num = httpWebRequest.Address.GetHashCode() ^ credentials.GetHashCode();
			return ((DigestSession)Cache[num])?.Authenticate(webRequest, credentials);
		}
	}
