				{
					IPAddress iPAddress = IPAddress.Parse(h_addrlist[i]);
					if ((Socket.OSSupportsIPv6 && iPAddress.AddressFamily == AddressFamily.InterNetworkV6) || (Socket.OSSupportsIPv4 && iPAddress.AddressFamily == AddressFamily.InterNetwork))
					{
