			{
				return true;
			}
			int num = 0;
			while (true)
			{
				IPEndPoint iPEndPoint = null;
				try
				{
					iPEndPoint = endPointCallback(this, remote, num);
				}
				catch
				{
					return false;
				}
				if (iPEndPoint == null)
				{
					return true;
				}
				try
				{
					sock.Bind(iPEndPoint);
				}
				catch (SocketException)
				{
					num = checked(num + 1);
					continue;
				}
				break;
			}
			return true;
