			}

			internal AsyncTaskMethodBuilder<TResult> GetCompletionResponsibility(out bool responsibleForReturningToPool)
			{
				lock (this)
				{
					responsibleForReturningToPool = _accessed;
					_accessed = true;
					_ = _builder.Task;
					return _builder;
