		{
			ThrowIfDisposedAndClosed();
			int error = 0;
			SafeSocketHandle safe_handle = Accept_internal(m_Handle, out error, is_blocking);
			if (error != 0)
			{
				if (is_closed)
				{
					error = 10004;
				}
				throw new SocketException(error);
