	public class TcpClient : IDisposable
	{
		private Socket m_ClientSocket;

		private bool m_Active;

		private NetworkStream m_DataStream;

		private AddressFamily m_Family = AddressFamily.InterNetwork;

		private bool m_CleanedUp;

		public Socket Client
		{
			get
			{
				return m_ClientSocket;
			}
			set
			{
				m_ClientSocket = value;
			}
		}

		public TcpClient()
			: this(AddressFamily.InterNetwork)
		{
			_ = Logging.On;
			_ = Logging.On;
		}

		public TcpClient(AddressFamily family)
		{
			_ = Logging.On;
			if (family != AddressFamily.InterNetwork && family != AddressFamily.InterNetworkV6)
			{
				throw new ArgumentException(global::SR.GetString("'{0}' Client can only accept InterNetwork or InterNetworkV6 addresses.", "TCP"), "family");
			}
			m_Family = family;
			initialize();
			_ = Logging.On;
		}

		public TcpClient(string hostname, int port)
		{
			_ = Logging.On;
			if (hostname == null)
			{
				throw new ArgumentNullException("hostname");
			}
			if (!ValidationHelper.ValidateTcpPort(port))
			{
				throw new ArgumentOutOfRangeException("port");
			}
			try
			{
				Connect(hostname, port);
			}
			catch (Exception ex)
			{
				if (ex is ThreadAbortException || ex is StackOverflowException || ex is OutOfMemoryException)
				{
					throw;
				}
				if (m_ClientSocket != null)
				{
					m_ClientSocket.Close();
				}
				throw ex;
			}
			_ = Logging.On;
		}

		public void Connect(string hostname, int port)
		{
			_ = Logging.On;
			if (m_CleanedUp)
			{
				throw new ObjectDisposedException(GetType().FullName);
			}
			if (hostname == null)
			{
				throw new ArgumentNullException("hostname");
			}
			if (!ValidationHelper.ValidateTcpPort(port))
			{
				throw new ArgumentOutOfRangeException("port");
			}
			if (m_Active)
			{
				throw new SocketException(SocketError.IsConnected);
			}
			IPAddress[] hostAddresses = Dns.GetHostAddresses(hostname);
			Exception ex = null;
			Socket socket = null;
			Socket socket2 = null;
			try
			{
				if (m_ClientSocket == null)
				{
					if (Socket.OSSupportsIPv4)
					{
						socket2 = new Socket(AddressFamily.InterNetwork, SocketType.Stream, ProtocolType.Tcp);
					}
					if (Socket.OSSupportsIPv6)
					{
						socket = new Socket(AddressFamily.InterNetworkV6, SocketType.Stream, ProtocolType.Tcp);
					}
				}
				IPAddress[] array = hostAddresses;
				foreach (IPAddress iPAddress in array)
				{
					try
					{
						if (m_ClientSocket == null)
						{
							if (iPAddress.AddressFamily == AddressFamily.InterNetwork && socket2 != null)
							{
								socket2.Connect(iPAddress, port);
								m_ClientSocket = socket2;
								socket?.Close();
							}
							else if (socket != null)
							{
								socket.Connect(iPAddress, port);
								m_ClientSocket = socket;
								socket2?.Close();
							}
							m_Family = iPAddress.AddressFamily;
							m_Active = true;
							break;
						}
						if (iPAddress.AddressFamily == m_Family)
						{
							Connect(new IPEndPoint(iPAddress, port));
							m_Active = true;
							break;
						}
					}
					catch (Exception ex2)
					{
						if (ex2 is ThreadAbortException || ex2 is StackOverflowException || ex2 is OutOfMemoryException)
						{
							throw;
						}
						ex = ex2;
					}
				}
			}
			catch (Exception ex3)
			{
				if (ex3 is ThreadAbortException || ex3 is StackOverflowException || ex3 is OutOfMemoryException)
				{
					throw;
				}
				ex = ex3;
			}
			finally
			{
				if (!m_Active)
				{
					socket?.Close();
					socket2?.Close();
					if (ex != null)
					{
						throw ex;
					}
					throw new SocketException(SocketError.NotConnected);
				}
			}
			_ = Logging.On;
		}

		public void Connect(IPEndPoint remoteEP)
		{
			_ = Logging.On;
			if (m_CleanedUp)
			{
				throw new ObjectDisposedException(GetType().FullName);
			}
			if (remoteEP == null)
			{
				throw new ArgumentNullException("remoteEP");
			}
			Client.Connect(remoteEP);
			m_Active = true;
			_ = Logging.On;
		}

		public IAsyncResult BeginConnect(string host, int port, AsyncCallback requestCallback, object state)
		{
			_ = Logging.On;
			IAsyncResult result = Client.BeginConnect(host, port, requestCallback, state);
			_ = Logging.On;
			return result;
		}

		public void EndConnect(IAsyncResult asyncResult)
		{
			_ = Logging.On;
			Client.EndConnect(asyncResult);
			m_Active = true;
			_ = Logging.On;
		}

		public Task ConnectAsync(string host, int port)
		{
			return Task.Factory.FromAsync(BeginConnect, EndConnect, host, port, null);
		}

		public NetworkStream GetStream()
		{
			_ = Logging.On;
			if (m_CleanedUp)
			{
				throw new ObjectDisposedException(GetType().FullName);
			}
			if (!Client.Connected)
			{
				throw new InvalidOperationException(global::SR.GetString("The operation is not allowed on non-connected sockets."));
			}
			if (m_DataStream == null)
			{
				m_DataStream = new NetworkStream(Client, ownsSocket: true);
			}
			_ = Logging.On;
			return m_DataStream;
		}

		public void Close()
		{
			_ = Logging.On;
			((IDisposable)this).Dispose();
			_ = Logging.On;
		}

		protected virtual void Dispose(bool disposing)
		{
			_ = Logging.On;
			if (m_CleanedUp)
			{
				_ = Logging.On;
				return;
			}
			if (disposing)
			{
				IDisposable dataStream = m_DataStream;
				if (dataStream != null)
				{
					dataStream.Dispose();
				}
				else
				{
					Socket client = Client;
					if (client != null)
					{
						try
						{
							client.InternalShutdown(SocketShutdown.Both);
						}
						finally
						{
							client.Close();
							Client = null;
						}
					}
				}
				GC.SuppressFinalize(this);
			}
			m_CleanedUp = true;
			_ = Logging.On;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
		}

		~TcpClient()
		{
			Dispose(disposing: false);
		}

		private void initialize()
		{
			Client = new Socket(m_Family, SocketType.Stream, ProtocolType.Tcp);
			m_Active = false;
		}
	}
	internal sealed class SafeSocketHandle : SafeHandleZeroOrMinusOneIsInvalid
	{
		private List<Thread> blocking_threads;

		private Dictionary<Thread, StackTrace> threads_stacktraces;

		private bool in_cleanup;

		private static bool THROW_ON_ABORT_RETRIES = Environment.GetEnvironmentVariable("MONO_TESTS_IN_PROGRESS") == "yes";

		public SafeSocketHandle(IntPtr preexistingHandle, bool ownsHandle)
			: base(ownsHandle)
		{
			SetHandle(preexistingHandle);
			if (THROW_ON_ABORT_RETRIES)
			{
				threads_stacktraces = new Dictionary<Thread, StackTrace>();
			}
		}

		protected override bool ReleaseHandle()
		{
			int error = 0;
			Socket.Blocking_icall(handle, block: false, out error);
			if (blocking_threads != null)
			{
				lock (blocking_threads)
				{
					int num = 0;
					while (blocking_threads.Count > 0)
					{
						if (num++ >= 10)
						{
							if (!THROW_ON_ABORT_RETRIES)
							{
								break;
							}
							StringBuilder stringBuilder = new StringBuilder();
							stringBuilder.AppendLine("Could not abort registered blocking threads before closing socket.");
							foreach (Thread blocking_thread in blocking_threads)
							{
								stringBuilder.AppendLine("Thread StackTrace:");
								stringBuilder.AppendLine(threads_stacktraces[blocking_thread].ToString());
							}
							stringBuilder.AppendLine();
							throw new Exception(stringBuilder.ToString());
						}
						if (blocking_threads.Count == 1 && blocking_threads[0] == Thread.CurrentThread)
						{
							break;
						}
						foreach (Thread blocking_thread2 in blocking_threads)
						{
							Socket.cancel_blocking_socket_operation(blocking_thread2);
						}
						in_cleanup = true;
						Monitor.Wait(blocking_threads, 100);
					}
				}
			}
			Socket.Close_icall(handle, out error);
			return error == 0;
		}

		public void RegisterForBlockingSyscall()
		{
			if (blocking_threads == null)
			{
				Interlocked.CompareExchange(ref blocking_threads, new List<Thread>(), null);
			}
			bool success = false;
			try
			{
				DangerousAddRef(ref success);
			}
			finally
			{
				lock (blocking_threads)
				{
					blocking_threads.Add(Thread.CurrentThread);
					if (THROW_ON_ABORT_RETRIES)
					{
						threads_stacktraces.Add(Thread.CurrentThread, new StackTrace(fNeedFileInfo: true));
					}
				}
				if (success)
				{
					DangerousRelease();
				}
				if (base.IsClosed)
				{
					throw new SocketException(10004);
				}
			}
		}

		public void UnRegisterForBlockingSyscall()
		{
			lock (blocking_threads)
			{
				Thread currentThread = Thread.CurrentThread;
				blocking_threads.Remove(currentThread);
				if (THROW_ON_ABORT_RETRIES && blocking_threads.IndexOf(currentThread) == -1)
				{
					threads_stacktraces.Remove(currentThread);
				}
				if (in_cleanup && blocking_threads.Count == 0)
				{
					Monitor.Pulse(blocking_threads);
				}
			}
		}
	}
