							.Append("\r\n");
					}
				}
				stringBuilder.Append("\r\n");
				return s_defaultHttpEncoding.GetBytes(stringBuilder.ToString());
			}
			finally
			{
				stringBuilder.Clear();
			}
		}

		private static KeyValuePair<string, string> CreateSecKeyAndSecWebSocketAccept()
		{
