			using SHA1 sHA = SHA1.Create();
			return new KeyValuePair<string, string>(text, Convert.ToBase64String(sHA.ComputeHash(Encoding.ASCII.GetBytes(text + "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"))));
