			}
		}

		private void SetAndVerifySelectionCallback(LocalCertificateSelectionCallback callback)
		{
			if (selectionCallback == null)
			{
				selectionCallback = callback;
				if (callback == null)
				{
					settings.ClientCertificateSelectionCallback = null;
					return;
				}
				settings.ClientCertificateSelectionCallback = (string t, System.Security.Cryptography.X509Certificates.X509CertificateCollection lc, System.Security.Cryptography.X509Certificates.X509Certificate rc, string[] ai) => callback(this, t, lc, rc, ai);
			}
			else if ((callback != null && selectionCallback != callback) || (explicitSettings && settings.ClientCertificateSelectionCallback != null))
			{
