			}
			if (data[index + 1] == MailBnfHelper.Dot)
			{
				throw new FormatException(global::SR.Format("An invalid character was found in the mail header: '{0}'.", MailBnfHelper.Dot));
			}
			return index;
		}
	}
	internal static class MailAddressParser
