		private static Encoding UTF8Unmarked
		{
			get
			{
				if (utf8unmarked == null)
				{
					utf8unmarked = new UTF8Encoding(encoderShouldEmitUTF8Identifier: false);
				}
				return utf8unmarked;
			}
		}

