		public bool UseDefaultCredentials => false;

		public SmtpClient()
			: this(null, 0)
		{
		}

		public SmtpClient(string host, int port)
		{
			defaultFrom = null;
			if (!string.IsNullOrEmpty(host))
			{
				this.host = host;
			}
			if (port != 0)
			{
