				-2 => "Internal error", 
				-3 => "Corrupted data", 
				-4 => "Not enough memory", 
				-5 => "Internal error (no progress possible)", 
				-6 => "Invalid version", 
				-10 => "Invalid argument(s)", 
				-11 => "IO error", 
				_ => "Unknown error", 
