		public InstanceDescriptor(MemberInfo member, ICollection arguments, bool isComplete)
		{
			MemberInfo = member;
			<IsComplete>k__BackingField = isComplete;
			if (arguments == null)
			{
				Arguments = Array.Empty<object>();
			}
			else
			{
