				break;
			case NotifyCollectionChangedAction.Remove:
				InitializeRemove(action, changedItems, startingIndex);
				break;
			}
		}

		private void InitializeAdd(NotifyCollectionChangedAction action, IList newItems, int newStartingIndex)
